-- 焦氏易林 D1 seed data (auto-generated from data/jiaoshi.json)

INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '111111', '雷天大壮，威震八方。正大光明，无往不利。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '011011', '雷风相薄，万物鼓舞。夫妇和合，家道丰裕。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('100100', '000000', '雷在地下，隐而未发。待时而动，一鸣惊人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '101010', '重明继照，元亨利贞。文明之治，万物咸亨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '111111', '日月丽天，光明遍照。四海承风，万邦来朝。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '010010', '水火相射，利害参半。进退维谷，须知存亡。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('101101', '000000', '火入地中，明夷之象。韬光养晦，以待天时。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '111111', '泽天夬决，果断行事。扬于王庭，孚号有厉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '001001', '泽山咸感，心意相通。少男少女，两情相悦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('110110', '000000', '泽在地上，聚众归一。王假有庙，利见大人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '101010', '水火既济，成功之象。万事遂心，功德圆满。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '111111', '龙升于天，达于帝庭。功成名就，富贵荣宁。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000111', '泰极否来，乐尽生悲。日中则昃，月满则亏。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '000000', '安居乐业，无忧无虑。鸡犬相闻，黍稷盈庑。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111000', '010101', '未济之象，功亏一篑。再接再厉，终有所成。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '101101', '火光烛天，英华发外。声名远播，朋友来聚。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '110110', '秋兰芬芳，桂酒椒浆。嘉宾满堂，福禄无疆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111000', '日出东方，光照万物。公侯之庭，受福多吉。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '111010', '甘雨时降，百谷丰收。嘉禾蕃庑，岁乐民丰。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000000', '大人垂衣裳，逍遥太自乐。神明扶持，人皆乐康。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '000111', '鸿雁南飞，避霜就温。不利久居，宜早迁移。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('111111', '010010', '涉河无梁，蹈火无足。危险之行，慎之又慎。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '100100', '雷动于地，万物出生。龙蛇起蛰，以和其庆。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111000', '春来万物生，天地和合。利见大人，百事吉昌。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '111111', '含元抱真，寿考且宁。不忧不惧，安乐以生。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '000111', '云覆日月，阴寒冰结。万物不生，忧愁且切。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000000', '010010', '水流东下，日月相过。暑往寒来，岁月消磨。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111000', '否极泰来，苦尽甘到。守得云开，月明风好。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '111111', '一飞冲天，龙跃在渊。贵不可言，福寿绵绵。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('000111', '000000', '归于本源，安分守己。无为而治，自然有序。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '101101', '明月出云，光照幽室。忧患消散，喜庆来集。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '111111', '水升于天，云行雨施。泽被万物，功德无量。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '000000', '水入于地，潜藏不见。静守待时，勿轻妄动。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('010010', '010010', '重险叠至，慎之又慎。坚心守正，终免灾患。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '100100', '风雷相益，进退有常。贤人在位，天下大安。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '111111', '风行天上，号令四方。小有亨通，利见大人。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('011011', '000000', '风在地上，广布德泽。观民设教，无远弗届。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '110110', '山泽损益，以诚相感。男女相悦，婚姻美满。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '111111', '山高天远，遁世离俗。知进知退，明哲保身。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001001', '000000', '两山重叠，止而又止。安居乐业，不轻妄动。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '100100', '旅之震。旅途惊变，出行不利。宜静守不宜远行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '101101', '旅之离。旅人得火照明，文书有利。但防火灾虚耗。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '110110', '旅之兑。旅途中遇悦事，小有欢娱。但不可贪恋，终须前行。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '111111', '旅之乾。旅人逢天，大有作为。但刚健太过，宜谦。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001111', '旅之遁。客居他乡思归，宜退不宜进。知止而退，明智之举。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '000000', '旅之坤。旅人归地，安定之象。利于落脚安居。', datetime('now'));
INSERT OR REPLACE INTO jiaoshi (ben_key, bian_key, text, created_at) VALUES ('001101', '001001', '旅之艮。旅人止步，不再前行。利于止息休整。', datetime('now'));
